VALUES
  ('bookkeeper-moex-01969', 'bookkeeper', 'bookkeeper-moex-102-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '根據上文，作者的父親認為力量很大時走出的大路與力量小時走出的小路，二者之 間真正的差異在於：', '["力量小者若跟隨力量大者的水路，亦可以快速到達河的彼岸", "力量大者須謙虛看待自己的成就，而力量小者則須對自己有信心，不怨天尤人", "所謂能者多勞，力量大者必須加倍付出心力，力量小者盡力即可，不能則止", "大路與小路的差別在於是否努力不懈、堅持到底，若半途而廢，大路亦不可得"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01970', 'bookkeeper', 'bookkeeper-moex-102-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '子曰：「羣居終日，言不及義，好行小慧，難矣哉！」（《論語．衛靈公》）下列 敘述，何者最能貼切說明上文中「好行小慧」的意義？', '["矯飾善行博取美好名聲", "喜歡運用私智僥倖行事", "不擇手段追求短暫利益", "專門結黨營私圖利個人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01971', 'bookkeeper', 'bookkeeper-moex-102-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '居是官者，當志其大，捨其細，先其急，後其緩，專利國家而不為身謀。彼汲汲於 名者，猶汲汲於利也。（司馬光〈諫院題名記〉）以下何者不屬於司馬光主張之諫 官應有品德？', '["不務苛細", "先辦急事", "急於求名", "不求私利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01972', 'bookkeeper', 'bookkeeper-moex-102-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '東昌卞氏，業牛醫者，有女小字臙脂，才姿惠麗。父寶愛之，欲占鳳於清門，而世 族鄙其寒賤，不屑締盟，以故及笄未字。對戶龔姓之妻王氏，佻脫善謔，女閨中談 友也。一日，送至門，見一少年過，白服裙帽，丰采甚都。女意似動，秋波縈轉之。 少年俯其首，趨而去。去既遠，女猶凝眺。王窺其意，戲之曰：「以娘子才貌，得 配若人，庶可無恨。」女暈紅上頰，脈脈不作一語。（蒲松齡〈臙脂〉）根據上文， 下列敘述何者錯誤？', '["女方出身寒門", "男方不解風情", "女方情竇初開", "王氏積極媒合 60210"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01973', 'bookkeeper', 'bookkeeper-moex-102-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '《世說新語．巧藝篇》曰：「顧長康畫人，或數年不點目精。人問其故，顧曰： 『四體妍蚩，本無關於妙處，傳神寫照，正在阿堵中。』」可知顧長康畫人首重：', '["形似", "妍蚩", "傳神", "色彩"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01974', 'bookkeeper', 'bookkeeper-moex-102-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '管仲既任政相齊，以區區之齊，在海濱，通貨積財，富國彊兵，與俗同好惡。故其 稱曰：「倉廩實而知禮節；衣食足而知榮辱。上服度，則六親固。四維不張，國乃 滅亡。下令如流水之原，令順民心。」故論卑而易行。俗之所欲，因而予之；俗之 所否，因而去之。（司馬遷《史記．管晏列傳》）文中「與俗同好惡」語義與下列 何者最為貼近？', '["好惡與聖人同", "民之所欲，常在我心", "作之君，作之親，作之師", "風俗之厚薄繫乎一二人心之所向"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01975', 'bookkeeper', 'bookkeeper-moex-102-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '《荀子》云：「術正而心順之，則形相雖惡而心術善，無害為君子也。形相雖善而 心術惡，無害為小人也。君子之謂吉，小人之謂凶。」根據上文，下列選項何者最 為貼近？', '["相人之術是一門重要的學問", "形貌美醜影響一個人的吉凶禍福", "吉凶以人格決定，不以形相決定", "形貌是一個人成為君子的重要條件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01976', 'bookkeeper', 'bookkeeper-moex-102-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '生活的藝術，有一部份我不是不能領略。我懂得怎麼看『七月巧雲』，聽蘇格蘭兵 吹 bagpipe，享受微風中的籐椅，吃鹽水花生，欣賞雨夜的霓虹燈，從雙層公共汽 車上伸出手摘樹巔的綠葉。在沒有人與人交接的場合，我充滿了生命的歡悅。可是 我一天不能克服這種咬嚙性的小煩惱，生命是一襲華美的袍，爬滿了蚤子。（張愛 玲〈天才夢〉）以下敘述何者錯誤？', '["作者懂得領略部分生活中的藝術", "作者在人與人交接的場合裡，容易感到不自在", "文中「咬嚙性的小煩惱」是指獨處的孤寂", "「生命是一襲華美的袍，爬滿了蚤子。」這是運用了「象徵」的手法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01977', 'bookkeeper', 'bookkeeper-moex-102-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '「世路中人，或圖功名，或治生產，儘自正經。爭奈天地間好風月、好山水、好書 籍，了不相涉，豈非枉卻一生？」關於以上文字的敘述，下列選項何者最為貼近？', '["本文旨在強調能享受生活樂趣的人，也才能在圖功名、治生產時有優異的表現", "「或圖功名，或治生產，儘自正經」，意指圖功名、治生產，都要以平常心去面對", "文中所謂「枉卻一生」者，乃指熱衷於功名、生產，卻不知在風月、山水、書籍 間找到生活樂趣的人", "「爭奈天地間好風月、好山水、好書籍，了不相涉」，意指遊覽自然風月山水， 與專心讀書，是截然不同的事 60210"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01978', 'bookkeeper', 'bookkeeper-moex-102-9a386a01', 'sub-bookkeeper-06', NULL, 'single_choice', '以下「」內的數字，何者為實際數目，而非虛數？', '["欲窮「千里」目，更上一層樓（王之渙〈登鸛鵲樓〉）", "「三顧」頻煩天下計，兩朝開濟老臣心（杜甫〈蜀相〉）", "相見時難別亦難，東風無力「百花」殘（李商隱〈無題〉）", "五花馬，千金裘，呼兒將出換美酒，與爾同銷「萬古」愁（李白〈將進酒〉） 那一雙傲慢的靴子至今還落在／高力士羞憤的手裡，人卻不見了／把滿地的難民和傷兵／ 把胡馬和羌笛交踐的節奏／留給杜二去細細的苦吟／自從那年賀知章眼花了／認你做 謫仙，便更加佯狂／用一隻中了魔咒的小酒壺／把自己藏起來，連太太也尋不到你／怨 長安城小而壺中天長（余光中）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:03+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "602", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
